  1	import * as React from 'react';
  2	import { useFormikContext, useField, FormikValues } from 'formik';
  3	import * as fuzzy from 'fuzzysearch';
  4	import { useTranslation } from 'react-i18next';
  5	import { AddTriggerFormValues, TriggerBindingKind } from '../../../types';
  6	import {
  7	  ClusterTriggerBindingModel,
  8	  TriggerBindingModel,
  9	} from '../../../models';
 10	import ResourceDropdown from '../../common/ResourceDropdown';
 11	import { getReferenceForModel } from '../../pipelines-overview/utils';
 12	import {
 13	  K8sResourceKind,
 14	  RedExclamationCircleIcon,
 15	  useK8sWatchResources,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import {
 18	  FormGroup,
 19	  FormHelperText,
 20	  HelperText,
 21	  HelperTextItem,
 22	} from '@patternfly/react-core';
 23	import { getFieldId } from '../../pipelines-details/multi-column-field/utils';
 24	import { useFormikValidationFix } from '../../pipelines-details/multi-column-field/formik-validation-fix';
 25	
 26	type TriggerBindingSelectorProps = {
 27	  description?: string;
 28	  label?: string;
 29	  onChange: (selectedTriggerBinding: TriggerBindingKind) => void;
 30	};
 31	
 32	const KEY_DIVIDER = '~';
 33	
 34	const TriggerBindingSelector: React.FC<TriggerBindingSelectorProps> = (
 35	  props,
 36	) => {
 37	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 38	  const {
 39	    description,
 40	    label = t(TriggerBindingModel.labelKey),
 41	    onChange,
 42	  } = props;
 43	  const { values } = useFormikContext<AddTriggerFormValues>();
 44	  const [field, { touched, error }] = useField('triggerBinding.name');
 45	  const { setFieldValue, setFieldTouched } = useFormikContext<FormikValues>();
 46	  const fieldId = getFieldId('triggerBinding.name', 'ns-dropdown');
 47	  const isValid = !(touched && error);
 48	  const errorMessage = !isValid ? error : '';
 49	  useFormikValidationFix(field.value);
 50	
 51	  const autoCompleteFilter = (
 52	    strText: string,
 53	    item: React.ReactElement,
 54	  ): boolean => fuzzy(strText, item?.props?.name);
 55	  const onTriggerChange = (
 56	    key: string,
 57	    value: string,
 58	    selectedResource: TriggerBindingKind,
 59	  ) => {
 60	    if (selectedResource) {
 61	      onChange && onChange(selectedResource);
 62	    }
 63	    setFieldValue('triggerBinding.name', key);
 64	    setFieldTouched('triggerBinding.name', true);
 65	  };
 66	
 67	  const resources = {
 68	    triggerBindingData: {
 69	      isList: true,
 70	      namespace: values.namespace,
 71	      kind: getReferenceForModel(TriggerBindingModel),
 72	      optional: true,
 73	    },
 74	    clusterTriggerBindingData: {
 75	      isList: true,
 76	      kind: getReferenceForModel(ClusterTriggerBindingModel),
 77	      optional: true,
 78	    },
 79	  };
 80	  const triggerBindings = useK8sWatchResources<{
 81	    triggerBindingData: TriggerBindingKind[];
 82	    clusterTriggerBindingData: K8sResourceKind[];
 83	  }>(resources);
 84	
 85	  return (
 86	    <FormGroup fieldId={fieldId} label={label} isRequired>
 87	      <ResourceDropdown
 88	        name="triggerBinding.name"
 89	        resources={[
 90	          {
 91	            kind: TriggerBindingModel.kind,
 92	            loaded: triggerBindings.triggerBindingData.loaded,
 93	            loadError: triggerBindings.triggerBindingData.loadError,
 94	            data: triggerBindings.triggerBindingData.data,
 95	          },
 96	          {
 97	            kind: ClusterTriggerBindingModel.kind,
 98	            loaded: triggerBindings.clusterTriggerBindingData.loaded,
 99	            loadError: triggerBindings.clusterTriggerBindingData.loadError,
100	            data: triggerBindings.clusterTriggerBindingData.data,
101	          },
102	        ]}
103	        loaded={
104	          triggerBindings.clusterTriggerBindingData.loaded ||
105	          triggerBindings.triggerBindingData.loaded
106	        }
107	        loadError={triggerBindings.triggerBindingData.loadError}
108	        autocompleteFilter={autoCompleteFilter}
109	        dataSelector={['metadata', 'name']}
110	        dropDownClassName="dropdown--full-width"
111	        customResourceKey={(key: string, resource: K8sResourceKind) => {
112	          const { kind } = resource;
113	          const order = kind === ClusterTriggerBindingModel.kind ? 2 : 1;
114	          return `${order}${KEY_DIVIDER}${key}`;
115	        }}
116	        placeholder={t('Select {{label}}', { label })}
117	        title={t('Select {{label}}', { label })}
118	        showBadge
119	        onChange={onTriggerChange}
120	      />
121	      <FormHelperText>
122	        <HelperText>
123	          {!isValid ? (
124	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
125	              {errorMessage}
126	            </HelperTextItem>
127	          ) : (
128	            <HelperTextItem>{description}</HelperTextItem>
129	          )}
130	        </HelperText>
131	      </FormHelperText>
132	    </FormGroup>
133	  );
134	};
135	
136	export default TriggerBindingSelector;

